<?php declare(strict_types=1); namespace App\Http\Requests\Payroll; use Illuminate\Foundation\Http\FormRequest; class StoreEmployeeSalaryProfileRequest extends FormRequest{public function authorize():bool{return $this->user()->can('salary-profiles.manage');} public function rules():array{return ['employee_id'=>'required|exists:employees,id','effective_start_date'=>'required|date','base_salary'=>'required|integer|min:0','payment_method'=>'required|string','bank_name'=>'nullable|string','bank_account_number'=>'nullable|string','bank_account_holder'=>'nullable|string','notes'=>'nullable|string','components'=>'array','components.*.payroll_component_id'=>'required_with:components|exists:payroll_components,id','components.*.amount'=>'required_with:components|integer|min:0'];}}
